// Assemble the gpt-image-2 EDIT prompt for the article poster. Initial renders
// paint approved content into an immutable master; feedback renders instead edit
// the latest finished poster. Image edits regenerate the whole canvas, so keeping
// unrequested layout and Devanagari text unchanged is necessarily best-effort.
const src = $input.first().json;
const headline = (src.headline || '').toString().trim();
const scene_brief = (src.scene_brief || '').toString().trim();
const reference_url = (src.reference_url || '').toString().trim();
const image_feedback = (src.image_feedback || '').toString().trim();
const panel_color = (src.panel_color || '').toString().trim();
const panel_color_name = (src.panel_color_name || '').toString().trim() || 'orange';
const headline_color = (src.headline_color || '').toString().trim() || '#7a1512';
const panel_desc = panel_color ? (panel_color_name + ' (' + panel_color + ')') : panel_color_name;

// Fail loud rather than editing a stale canonical master: the API must send either
// the selected immutable master (initial render) or latest poster (feedback).
if (!reference_url) { throw new Error('No "reference_url" received in the webhook body — the API must send the image URL to edit.'); }

let prompt;
if (image_feedback) {
  prompt = [
    'You are editing an existing finished DGIPR Maharashtra government ARTICLE poster provided as the input image.',
    'Apply ONLY this requested change: «' + image_feedback + '».',
    'Keep the exact layout, महासंवाद logo, curved accent side panel, existing Marathi headline text, navy department footer band and its text, white social-handle strip, colours, typography, and photograph unchanged except where the requested change explicitly requires it.',
    'Add no new text, letters, numbers, captions, logos, borders, or decorative elements. Preserve all existing Devanagari text exactly. Output ONE complete landscape poster filling the canvas.',
  ].join('\n');
} else {
  if (!headline) { throw new Error('No "headline" received in the webhook body.'); }
  prompt = [
    'You are editing an OFFICIAL DGIPR Maharashtra government ARTICLE poster: a single landscape banner.',
    'KEEP the master template layout EXACTLY as provided — same overall layout and proportions, the महासंवाद logo card in the top-left, the navy department footer band that reads "माहिती व जनसंपर्क महासंचालनालय, महाराष्ट्र शासन", and the white social-handle strip along the very bottom. Do NOT move, restyle, recolour, remove or duplicate the logo card, the footer band or the handle strip, and do not change the footer text.',
    '',
    'REPLACE these three things, inside the master\'s existing zones:',
    '',
    '1) PANEL COLOUR — recolour the curved left headline panel to ' + panel_desc + ', a solid flat fill covering the same panel shape and area as in the master. Recolour ONLY this panel; leave the logo card, footer band and handle strip exactly as they are.',
    '',
    '2) HEADLINE — erase the existing Marathi headline on the left panel and typeset THIS headline in its place, spelled EXACTLY as given, in correct Devanagari (Marathi). Colour ' + headline_color + ', bold (weight 900), centered on the recoloured panel, large and crisply legible. This is the ONLY text you add anywhere on the poster.',
    'HEADLINE (verbatim, do not translate or alter): ' + headline,
    '',
    '3) PHOTO — erase the existing farmer photo and fill the right-hand curved photo zone with a NEW realistic documentary photograph matching the description below. Keep the human subject on the RIGHT and a calmer, less-busy LEFT third so the headline panel stays fully readable. The photo must contain NO text, words, letters, numbers or logos.',
    'PHOTO (background imagery only): ' + (scene_brief || 'a relevant Maharashtra public-welfare documentary scene'),
    '',
    'Add NO other text: no subhead, no bullet points, no statistics, no quotes, no extra logos, no captions, and no outer border. Output ONE complete poster filling the whole canvas.',
  ].join('\n');
}

return [{ json: { prompt, headline, scene_brief, reference_url, image_feedback, generation_id: src.generation_id } }];
